import{_ as t,c as e,o as l,V as o}from"./chunks/framework.35c8bad0.js";const y=JSON.parse('{"title":"面试题[浏览器]","description":"","frontmatter":{"title":"面试题[浏览器]","date":"2023-05-25T00:00:00.000Z"},"headers":[],"relativePath":"blog/interview/230525.md","lastUpdated":1778465886000}'),r={name:"blog/interview/230525.md"},i=o(`<h1 id="面试题-浏览器" tabindex="-1">面试题[浏览器] <a class="header-anchor" href="#面试题-浏览器" aria-label="Permalink to &quot;面试题[浏览器]&quot;">​</a></h1><h2 id="_1-浏览器基础" tabindex="-1">1. 浏览器基础 <a class="header-anchor" href="#_1-浏览器基础" aria-label="Permalink to &quot;1. 浏览器基础&quot;">​</a></h2><h3 id="_1-1-常见浏览器所用内核" tabindex="-1">1.1 常见浏览器所用内核 <a class="header-anchor" href="#_1-1-常见浏览器所用内核" aria-label="Permalink to &quot;1.1 常见浏览器所用内核&quot;">​</a></h3><p>目前主流的浏览器内核主要有三个：Google主导的 <strong>Blink</strong>、Mozilla的 <strong>Gecko</strong>，以及苹果的 <strong>WebKit</strong>。它们共同构成了现今浏览器技术的核心。</p><p>主流桌面浏览器及其内核：</p><table><thead><tr><th style="text-align:left;">浏览器</th><th style="text-align:left;">内核</th><th style="text-align:left;">说明</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>Google Chrome</strong></td><td style="text-align:left;">Blink</td><td style="text-align:left;">由 Google 基于 WebKit 开发，是目前全球使用最广泛的浏览器引擎。</td></tr><tr><td style="text-align:left;"><strong>Microsoft Edge</strong></td><td style="text-align:left;">Blink</td><td style="text-align:left;">微软已全面转向 <strong>Blink</strong>，弃用自研的 EdgeHTML 内核，性能显著提升，兼容 Chrome 插件。</td></tr><tr><td style="text-align:left;"><strong>Mozilla Firefox</strong></td><td style="text-align:left;">Gecko</td><td style="text-align:left;">开源且注重标准、隐私与安全，是除 Blink 外最主流的独立内核之一。</td></tr><tr><td style="text-align:left;"><strong>Apple Safari</strong></td><td style="text-align:left;">WebKit</td><td style="text-align:left;">苹果所有设备的默认浏览器，对苹果生态有深度优化和极佳的性能稳定性。</td></tr><tr><td style="text-align:left;"><strong>Opera</strong></td><td style="text-align:left;">Blink</td><td style="text-align:left;">早期曾采用自研的 Presto 内核（已停用），现已全面转向 <strong>Blink</strong> 内核。</td></tr><tr><td style="text-align:left;"><strong>Brave</strong></td><td style="text-align:left;">Blink</td><td style="text-align:left;">主打隐私保护的浏览器，基于 <strong>Blink</strong> 内核开发。</td></tr><tr><td style="text-align:left;"><strong>Vivaldi</strong></td><td style="text-align:left;">Blink</td><td style="text-align:left;">主打高定制性，同样基于 <strong>Blink</strong> 内核。</td></tr></tbody></table><p>内核演进趋势总结：</p><ul><li><strong>技术演进</strong>：浏览器内核从早期的 <strong>Trident</strong>（IE）、<strong>Presto</strong>（Opera 旧版）等百花齐放，经过激烈竞争，最终收敛到由 Blink、Gecko、WebKit 三足鼎立的局面。</li><li><strong>Chromium 主导</strong>：Blink(Chromium) 内核凭借强大的性能、活跃的开源社区和标准支持，已占据绝对主导地位，市场份额超过 <strong>80%</strong>，Edge、Opera、Vivaldi 等均已成为其生态一员。</li><li><strong>弱肉强食的市场</strong>：浏览器内核已成为门槛极高的领域，需要巨大的持续投入。Edge 放弃自研 EdgeHTML 转投 Chromium，正是这一趋势的体现。</li></ul><h3 id="_1-2-浏览器渲染页面的过程" tabindex="-1">1.2 浏览器渲染页面的过程 <a class="header-anchor" href="#_1-2-浏览器渲染页面的过程" aria-label="Permalink to &quot;1.2 浏览器渲染页面的过程&quot;">​</a></h3><p>浏览器渲染页面的过程是一个复杂而精细的任务，它涉及多个步骤和组件的协同工作。以下是浏览器渲染页面的主要过程：</p><ol><li><strong>HTML解析与DOM树构建</strong>： <ul><li>浏览器从网络获取HTML文件，并从上到下逐行解析。</li><li>在解析过程中，浏览器会构建文档对象模型（DOM），这是一个表示HTML文档结构的树形数据结构。DOM的节点与HTML文档中的标签、文本节点和属性相对应。</li></ul></li><li><strong>CSS解析与CSSOM树构建</strong>： <ul><li>与HTML解析并行，浏览器还会解析外部和内部的CSS样式表。</li><li>CSS解析后，会生成CSS对象模型（CSSOM），这也是一个树形结构，描述了页面上所有的CSS选择器及其层级结构和属性。</li></ul></li><li><strong>渲染树生成</strong>： <ul><li>一旦DOM和CSSOM都构建完成，浏览器会结合这两个树生成渲染树（Render Tree）。</li><li>渲染树只包含需要显示的节点和样式信息，例如，设置了<code>display: none</code>的节点不会出现在渲染树中。</li></ul></li><li><strong>布局处理</strong>： <ul><li>渲染树生成后，浏览器会进行布局处理，也称为回流（Reflow）。</li><li>布局处理阶段，浏览器会根据CSS样式信息为渲染树中的每个节点计算其位置和尺寸。这涉及到复杂的盒模型计算，以确保元素在页面上正确排列。</li></ul></li><li><strong>绘制</strong>： <ul><li>在布局处理完成后，浏览器会进入绘制阶段。</li><li>绘制阶段，浏览器会遍历渲染树，将每个节点的内容绘制到屏幕上。这是一个渐进式的过程，边解析边绘制，以提高用户体验。</li></ul></li><li><strong>JavaScript执行</strong>： <ul><li>在HTML解析过程中，如果遇到<code>&lt;script&gt;</code>标签，浏览器会暂停HTML解析，等待JavaScript文件下载并执行。</li><li>JavaScript代码可能会修改DOM或CSSOM，从而导致回流和重绘。因此，JavaScript的执行顺序和性能对页面渲染有很大影响。</li><li>需要注意的是，使用<code>defer</code>或<code>async</code>属性可以改变JavaScript的加载和执行方式，以优化页面性能。</li></ul></li><li><strong>分层与合成</strong>（可选）： <ul><li>对于复杂的页面，浏览器可能会将页面分成多个图层（Layer），以提高渲染效率。</li><li>每个图层都会单独生成绘制指令，并交给合成器线程进行合成和栅格化。</li><li>合成器线程会将图层合并成一个完整的图像，然后显示在屏幕上。</li></ul></li></ol><p>此外，在渲染过程中，浏览器还会进行性能优化，如懒加载、按需加载、资源压缩等，以提高页面加载速度和用户体验。</p><h3 id="_1-3-现代浏览器多进程" tabindex="-1">1.3 现代浏览器多进程 <a class="header-anchor" href="#_1-3-现代浏览器多进程" aria-label="Permalink to &quot;1.3 现代浏览器多进程&quot;">​</a></h3><p>现代浏览器采用多进程架构，主要包括以下几个常见的进程：</p><ol><li>浏览器主进程（Browser Process）：也称为浏览器引擎进程或浏览器内核进程，负责协调和管理整个浏览器的工作。它处理用户界面、显示和用户交互，还管理其他子进程。</li><li>渲染进程（Renderer Process）：每个标签页或窗口都会有一个独立的渲染进程，负责处理网页内容的渲染。渲染进程使用浏览器的渲染引擎来解析 HTML、CSS，构建渲染树并进行页面布局和绘制。</li><li>插件进程（Plugin Process）：用于运行浏览器插件，如Flash Player、PDF 阅读器等。为了增强安全性和稳定性，现代浏览器已经逐渐停止对插件的支持。</li><li>GPU 进程（GPU Process）：处理图形相关的任务，如页面的绘制和图形加速。它负责使用计算机的 GPU（图形处理器）来执行图形操作，提高页面渲染的性能。</li><li>网络进程（Network Process）：处理网络请求和响应，负责发送和接收网络数据。它负责与服务器通信，下载网页内容、样式、脚本以及其他资源。</li><li>JavaScript 引擎进程（JavaScript Engine Process）：负责解析和执行 JavaScript 代码。现代浏览器通常使用高性能的 JavaScript 引擎，如V8引擎，它在单独的进程中运行。</li></ol><p>这些进程通过进程间通信（IPC）进行通信和协调，以实现浏览器的各种功能。多进程架构的设计可以提高浏览器的安全性、稳定性和性能，同时隔离不同的任务，避免一个标签页或插件的崩溃影响整个浏览器的运行。</p><h3 id="_1-4-浏览器渲染进程" tabindex="-1">1.4 浏览器渲染进程 <a class="header-anchor" href="#_1-4-浏览器渲染进程" aria-label="Permalink to &quot;1.4 浏览器渲染进程&quot;">​</a></h3><p>渲染进程是浏览器中负责处理网页渲染的核心组件之一。它负责将 HTML、CSS 和 JavaScript 转换为可视化的网页内容，以供用户在浏览器中查看和与之交互。</p><p>以下是渲染进程的主要功能和工作流程：</p><ol><li>解析 HTML：渲染进程接收到网络传输的 HTML 文档后，通过解析器逐行读取并解析文档结构。解析器将 HTML 标记转换为解析树（DOM 树）。</li><li>构建渲染树：基于 DOM 树和 CSS 样式信息，渲染进程构建渲染树（Render Tree）。渲染树由可视化的网页内容组成，其中每个节点都与其对应的样式信息关联。</li><li>布局（Layout）：渲染树中的每个节点都包含了位置和尺寸信息。布局引擎根据这些信息，计算出每个节点在屏幕上的精确位置，并生成布局（Layout）。</li><li>绘制（Painting）：渲染进程使用绘图引擎将布局转换为可视化的像素信息，即绘制。绘制涉及颜色、字体、图像等元素的渲染。</li><li>合成（Compositing）：渲染进程将绘制的结果合成为最终的页面图像。这涉及将多个图层（Layer）合并，并按正确的顺序进行显示。</li><li>显示和交互：最终，渲染进程将渲染好的页面图像显示在浏览器窗口上，用户可以与之交互。渲染进程还负责处理用户的输入事件，并将其传递给相应的处理程序。</li></ol><p>需要注意的是，现代浏览器通常采用多进程架构，其中渲染进程是其中之一。其他进程如网络进程、JavaScript 引擎进程和浏览器主进程等也扮演着不同的角色，协同工作来实现浏览器的功能。渲染进程与这些进程之间通过进程间通信（IPC）来进行数据交换和协调。</p><h3 id="_1-5-dom-树是怎么生成的" tabindex="-1">1.5 DOM 树是怎么生成的 <a class="header-anchor" href="#_1-5-dom-树是怎么生成的" aria-label="Permalink to &quot;1.5 DOM 树是怎么生成的&quot;">​</a></h3><p>DOM 树（Document Object Model Tree）的生成过程，本质上是浏览器将 <strong>HTML 文本</strong> 解析为 <strong>树状结构</strong> 的过程。这个解析过程由浏览器的 <strong>HTML 解析器</strong> 负责，它会逐字节读取 HTML，并遵循一套标准化的算法（参考 HTML 规范中的 <strong>标记化</strong> 和 <strong>树构建</strong> 环节）。整体流程图：</p><div class="language- line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki material-theme-palenight"><code><span class="line"><span style="color:#A6ACCD;">原始 HTML 字节流 → 解码 → 字符流 → 词法分析 → 令牌流 → 语法分析（树构建） → DOM 树</span></span>
<span class="line"><span style="color:#A6ACCD;">                     ↑                                 ↓</span></span>
<span class="line"><span style="color:#A6ACCD;">                   编码元信息                      脚本执行（可能阻断）</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><h2 id="_2-浏览器进阶" tabindex="-1">2. 浏览器进阶 <a class="header-anchor" href="#_2-浏览器进阶" aria-label="Permalink to &quot;2. 浏览器进阶&quot;">​</a></h2><h3 id="_2-1-跨域问题" tabindex="-1">2.1 跨域问题 <a class="header-anchor" href="#_2-1-跨域问题" aria-label="Permalink to &quot;2.1 跨域问题&quot;">​</a></h3><ol><li><p>什么是跨域</p><p><strong>跨域</strong>指的是浏览器请求一个<strong>不同源</strong>的资源。而“源”（Origin）由三部分组成：</p><ul><li><strong>协议</strong>（如 <code>http://</code> 或 <code>https://</code>）</li><li><strong>域名</strong>（如 <code>example.com</code>）</li><li><strong>端口</strong>（如 <code>80</code>、<code>443</code>、<code>8080</code>，当端口与协议默认端口不同时）</li></ul><p>只有当<strong>协议、域名、端口三者完全一致</strong>时，才叫同源；只要有一个不同，就是<strong>跨域</strong>。</p><blockquote><p>注意：<code>localhost</code> 和 <code>127.0.0.1</code> 虽然指向同一台机器，但浏览器认为它们是不同的域名，因此也是跨域。</p></blockquote></li><li><p>为什么浏览器要限制跨域</p><p>这是为了保障用户安全，核心机制叫做<strong>同源策略（Same-Origin Policy）</strong>。如果没有同源策略，恶意网站可以随意读取你在其他网站（如网银、邮箱）上的数据。例如：</p><ul><li>你登录了银行网站 <code>bank.com</code>（Cookie 存储在浏览器中）。</li><li>然后你访问了一个恶意网站 <code>evil.com</code>。</li><li><code>evil.com</code> 的脚本可以发起请求到 <code>bank.com/api/account</code>，由于浏览器会自动带上 <code>bank.com</code> 的 Cookie，恶意网站就能获取你的账户信息。</li></ul><p><strong>同源策略</strong> 阻止这种操作：只有同源的脚本才能读取另一个源的响应内容。<strong>浏览器</strong>会拦截跨域请求的响应，不允许当前页面的 JavaScript 读取，但<strong>请求本身</strong>有时还是会发出（取决于请求类型）。这样就隔离了不同源的数据。</p><blockquote><p>注意：跨域限制是<strong>浏览器</strong>施加的，不是服务器。如果你用 Postman、curl 等工具直接请求接口，不存在跨域问题。</p></blockquote></li><li><p>解决跨域的常见方法</p><ul><li><p><strong>CORS（跨域资源共享）</strong>—— 最正统、最常用：CORS（Cross-Origin Resource Sharing）是通过服务器在<strong>响应头中添加特定字段</strong>，告诉浏览器允许跨域访问。</p><p>关键响应头：</p><ul><li><code>Access-Control-Allow-Origin</code>：指定允许的源（<code>*</code> 表示任意源，但不能与凭证头一起用）</li><li><code>Access-Control-Allow-Methods</code>：允许的 HTTP 方法（如 GET, POST）</li><li><code>Access-Control-Allow-Headers</code>：允许的自定义请求头</li><li><code>Access-Control-Allow-Credentials</code>：是否允许携带 Cookie（设为 <code>true</code> 时需要指定具体源，不能用 <code>*</code>）</li><li><code>Access-Control-Max-Age</code>：预检请求的缓存时间</li></ul></li><li><p><strong>JSONP（JSON with Padding）</strong>—— 仅限 GET 请求，老项目中常见：利用 <code>&lt;script&gt;</code> 标签不受跨域限制，让服务器返回一段 JavaScript 代码（调用前端预定义的回调函数）。</p></li><li><p><strong>代理（Proxy）</strong>—— 前端开发中最常用的临时方案：在<strong>同源</strong>的中间层转发请求，绕过浏览器限制。</p><ul><li>开发环境代理（CRA、Vite、Webpack devServer）</li><li>Nginx 反向代理</li></ul></li><li><p><strong>postMessage（跨文档通信）</strong>：用于 <code>iframe</code>、弹出窗口之间跨域传递消息。</p></li><li><p><strong>WebSocket</strong>：WebSocket 本身<strong>不受同源策略限制</strong>（但 WebSocket 协议有 <code>Origin</code> 头部，服务器可以校验）。因此可以通过 WebSocket 实现跨域通信。</p></li><li><p><strong>最佳实践</strong>：</p><ul><li>生产环境：优先采用 <strong>CORS</strong> 进行精细化配置。</li><li>开发环境：使用脚手架自带的 <strong>proxy</strong> 功能。</li><li>特殊场景（iframe）：使用 <strong>postMessage</strong>。</li></ul></li></ul></li></ol><h3 id="_2-2-浏览器存储" tabindex="-1">2.2 浏览器存储 <a class="header-anchor" href="#_2-2-浏览器存储" aria-label="Permalink to &quot;2.2 浏览器存储&quot;">​</a></h3><p>浏览器存储指的是浏览器用于在客户端保存和管理数据的机制。以下是几种常见的浏览器存储方式：</p><table><thead><tr><th style="text-align:left;">存储方式</th><th style="text-align:left;">容量（典型）</th><th style="text-align:left;">生命周期</th><th style="text-align:left;">作用域</th><th style="text-align:left;">同步/异步</th><th style="text-align:left;">数据类型</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>Cookie</strong></td><td style="text-align:left;">4KB</td><td style="text-align:left;">可设置过期时间</td><td style="text-align:left;">同源，可设置路径域</td><td style="text-align:left;">同步</td><td style="text-align:left;">字符串</td></tr><tr><td style="text-align:left;"><strong>localStorage</strong></td><td style="text-align:left;">5-10MB</td><td style="text-align:left;">永久（除非手动清除）</td><td style="text-align:left;">同源（协议+域名+端口）</td><td style="text-align:left;">同步</td><td style="text-align:left;">字符串（键值对）</td></tr><tr><td style="text-align:left;"><strong>sessionStorage</strong></td><td style="text-align:left;">5-10MB</td><td style="text-align:left;">标签页关闭即消失</td><td style="text-align:left;">同源 + 同会话（同一标签页）</td><td style="text-align:left;">同步</td><td style="text-align:left;">字符串（键值对）</td></tr><tr><td style="text-align:left;"><strong>IndexedDB</strong></td><td style="text-align:left;">通常 &gt;250MB，甚至 GB 级</td><td style="text-align:left;">永久（除非手动清除）</td><td style="text-align:left;">同源（可跨多个 Tab）</td><td style="text-align:left;">异步</td><td style="text-align:left;">任何结构的数据（对象、二进制、文件等）</td></tr><tr><td style="text-align:left;"><strong>Cache Storage</strong></td><td style="text-align:left;">取决于可用磁盘空间（浏览器管理）</td><td style="text-align:left;">永久（除非清除或 LRU 淘汰）</td><td style="text-align:left;">同源（Service Worker 控制）</td><td style="text-align:left;">异步</td><td style="text-align:left;">Response 对象 （HTTP 请求/响应对）</td></tr><tr><td style="text-align:left;"><strong>File System Access API</strong></td><td style="text-align:left;">取决于用户授权</td><td style="text-align:left;">永久（用户授权后）</td><td style="text-align:left;">同源 + 用户授权</td><td style="text-align:left;">异步</td><td style="text-align:left;">文件和目录</td></tr></tbody></table><p>各存储方式详解：</p><ol><li>Cookie <ul><li><strong>本质</strong>：服务器发送给浏览器的少量数据，浏览器后续请求会自动携带（通过 <code>Cookie</code> 请求头）。</li><li><strong>操作接口</strong>：<code>document.cookie</code>（字符串读写）。</li><li><strong>容量</strong>：每个 Cookie 最大 4KB，每个域名下 Cookie 总数有限（约 20-50 个，取决于浏览器）。</li><li><strong>生命周期</strong>：可设置 <code>Expires</code> 或 <code>Max-Age</code>，若未设置则为会话 Cookie（关闭浏览器失效）。</li><li><strong>作用域</strong>：由 <code>Domain</code> 和 <code>Path</code> 属性决定；默认仅为当前域名及路径，但不包括子域（除非显式设置 Domain）。</li><li><strong>安全性</strong>：可设置 <code>HttpOnly</code>（禁止 JS 访问，防 XSS）、<code>Secure</code>（仅 HTTPS 传输）、<code>SameSite</code>（防 CSRF）。</li><li><strong>使用场景</strong>： <ul><li>身份认证凭证（Session ID）</li><li>少量用户偏好</li><li>跟踪用户行为（但受隐私政策限制）</li></ul></li></ul></li><li>Web Storage（localStorage 和 sessionStorage） <ul><li><strong>共同特点</strong>： <ul><li>键值对存储，键和值都必须是字符串（非字符串会被转为字符串，存对象需 <code>JSON.stringify()</code>）。</li><li>提供同步 API：<code>setItem(key, value)</code>、<code>getItem(key)</code>、<code>removeItem(key)</code>、<code>clear()</code>。</li><li>可监听 <code>storage</code> 事件（同源下其他标签页修改存储可收到通知，但修改自身页面不触发）。</li></ul></li><li><strong>localStorage</strong>： <ul><li>永久存储，除非用户清除网站数据或调用 <code>clear()</code>。</li><li>作用域：同源（协议、域名、端口都相同）的所有标签页/窗口共享。</li></ul></li><li><strong>sessionStorage</strong>： <ul><li>生命周期为<strong>页面会话</strong>：关闭标签页或浏览器则消失（页面重载或恢复不会丢失，但打开新标签页会创建新会话，不共享）。</li><li>作用域：同源且<strong>同一浏览上下文组</strong>（即同一个标签页中多个 iframe 也算同一会话；但同源的不同标签页之间不共享）。</li></ul></li><li><strong>容量</strong>：通常 5MB~10MB（不同浏览器差异）。</li></ul></li><li>IndexedDB <ul><li><strong>本质</strong>：一个事务型、对象仓库式的 NoSQL 数据库，运行在浏览器中。</li><li><strong>容量</strong>：通常远大于 localStorage（桌面端可达几百 MB 甚至 GB 级别，具体取决于磁盘空间）。</li><li><strong>API</strong>：异步、基于事件回调或 Promise（现代封装如 <code>idb</code> 库使之更易用）。</li><li><strong>特点</strong>： <ul><li>支持索引、游标、事务（ACID 部分保证）。</li><li>可存储大量结构化数据，包括 Blob（二进制大对象）、ArrayBuffer、File 等。</li><li>支持版本升级 migration。</li><li>同源策略限制。</li></ul></li></ul></li><li>Cache Storage <ul><li><strong>本质</strong>：Service Worker 规范的一部分，用于缓存网络请求的 <code>Request</code> 和 <code>Response</code> 对。</li><li><strong>API</strong>：<code>caches</code> 全局对象，提供 <code>open</code>、<code>match</code>、<code>put</code>、<code>delete</code>、<code>keys</code> 等异步方法。</li><li><strong>生命周期</strong>：持久化存储，除非用户清除站点数据或浏览器因磁盘压力而驱逐（通常会优先清理不常使用的缓存）。</li><li><strong>作用域</strong>：Service Worker 作用范围内的所有页面共享（但 Service Worker 本身可控制具体哪些请求被缓存）。</li><li><strong>使用场景</strong>： <ul><li>PWA：实现离线浏览、缓存静态资源（HTML、CSS、JS、图片）。</li><li>自定义网络策略（Cache First, Network First 等）。</li></ul></li></ul></li><li>File System Access API <ul><li><strong>本质</strong>：允许 Web 应用直接读写用户本地文件或文件夹（需获得用户授权）。</li><li><strong>API</strong>：<code>window.showOpenFilePicker</code>、<code>showSaveFilePicker</code>、<code>showDirectoryPicker</code>，返回 <code>FileSystemFileHandle</code> 等对象。</li><li><strong>容量</strong>：不限（受限于用户磁盘空间），每次读写都需要用户明确授权。</li><li><strong>生命周期</strong>：授权后可永久访问，直至用户撤销权限或清除站点数据。</li><li><strong>使用场景</strong>： <ul><li>在线 IDE、图片编辑器、文档编辑器，直接编辑本地文件。</li><li>需要访问本地目录进行批量处理的应用。</li></ul></li><li><strong>兼容性</strong>：较新（Chrome 86+，Edge，Opera；Firefox 和 Safari 未支持或部分支持）。</li></ul></li></ol><h3 id="_2-3-浏览器缓存" tabindex="-1">2.3 浏览器缓存 <a class="header-anchor" href="#_2-3-浏览器缓存" aria-label="Permalink to &quot;2.3 浏览器缓存&quot;">​</a></h3><p>浏览器缓存是前端性能优化中非常重要的一环，它能显著减少网络请求、降低带宽消耗、加快页面加载速度。</p><ol><li><p>浏览器缓存的位置</p><p>浏览器缓存可以存储在多个地方，按优先级从高到低：</p><ol><li><strong>内存缓存（Memory Cache）</strong>：存储在内存中，速度最快，但容量小，进程结束后释放（如关闭标签页）。通常用于加载页面过程中短暂存在的资源（如解析 HTML 时的 CSS、JS）。</li><li><strong>硬盘缓存（Disk Cache）</strong>：存储在磁盘上，容量大，持久化存储。即使关闭浏览器再打开，缓存依然存在。速度比内存慢，但比网络请求快很多。</li><li><strong>Service Worker 缓存</strong>：由开发者通过 Service Worker 脚本控制，可以拦截请求并返回自定义缓存。优先级最高，一旦 Service Worker 接管，可以决定是否走网络或使用缓存。</li><li><strong>推送缓存（Push Cache）</strong>：HTTP/2 中服务器推送的资源会被缓存在这个特定区域，生命周期较短，只在当前会话有效。</li></ol><p>实际请求时，浏览器会按照 <strong>Service Worker → 内存缓存 → 硬盘缓存 → 推送缓存</strong> 的顺序寻找缓存。如果都没有，再发起网络请求。</p></li><li><p>缓存策略总览</p><p>浏览器缓存主要分为两大策略：<strong>强缓存</strong> 和 <strong>协商缓存</strong>。它们的核心区别在于：是否需要向服务器验证缓存是否有效。</p><table><thead><tr><th style="text-align:left;">策略</th><th style="text-align:left;">判定依据</th><th style="text-align:left;">是否发送请求</th><th style="text-align:left;">谁决定</th><th style="text-align:left;">响应状态码</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>强缓存</strong></td><td style="text-align:left;">本地缓存未过期</td><td style="text-align:left;">否（直接使用本地）</td><td style="text-align:left;">本地浏览器</td><td style="text-align:left;">200 (from disk/memory cache)</td></tr><tr><td style="text-align:left;"><strong>协商缓存</strong></td><td style="text-align:left;">缓存已过期或不确定</td><td style="text-align:left;">是（请求带上验证标识）</td><td style="text-align:left;">服务器</td><td style="text-align:left;">304 Not Modified 或 200</td></tr></tbody></table></li></ol><h3 id="_2-4-浏览器存储和浏览器缓存的区别" tabindex="-1">2.4 浏览器存储和浏览器缓存的区别 <a class="header-anchor" href="#_2-4-浏览器存储和浏览器缓存的区别" aria-label="Permalink to &quot;2.4 浏览器存储和浏览器缓存的区别&quot;">​</a></h3><p>浏览器存储（Browser Storage）：指的是<strong>浏览器在客户端（用户的设备）上保存和管理数据的机制</strong>。它主要用于在浏览器中存储数据，以供后续的访问和使用。常见的浏览器存储机制包括 Cookie、Web Storage（sessionStorage 和 localStorage）、IndexedDB 等。这些存储机制可用于存储用户首选项、会话数据、缓存数据等。浏览器存储是由开发者主动使用相应的 API 将数据存储在客户端，并通过 API 进行读取和更新。</p><p>浏览器缓存（Browser Cache）：是指<strong>浏览器在本地缓存网页资源，以便在后续的访问中能够更快地加载和呈现页面内容</strong>。浏览器缓存的主要目的是减少网络请求，提高网页的加载速度和性能。当浏览器首次请求某个资源时，它会检查是否存在缓存的副本，如果存在且仍然有效，则直接从缓存中获取资源而不是向服务器重新请求。常见的缓存机制包括浏览器缓存、Service Worker 缓存和 HTTP 缓存。浏览器缓存是由浏览器根据服务器返回的响应头中的缓存相关字段来决定资源是否被缓存以及缓存的有效期。</p><p>核心区别一句话总结：</p><ul><li><strong>浏览器存储</strong>：存的是<strong>你自己定义的数据</strong>，你决定什么时候读、写。</li><li><strong>浏览器缓存</strong>：存的是<strong>网络请求回来的资源</strong>，浏览器根据服务器指示自动决定是否复用。</li></ul><h3 id="_2-5-浏览器缓存和-http-缓存的区别" tabindex="-1">2.5 浏览器缓存和 HTTP 缓存的区别 <a class="header-anchor" href="#_2-5-浏览器缓存和-http-缓存的区别" aria-label="Permalink to &quot;2.5 浏览器缓存和 HTTP 缓存的区别&quot;">​</a></h3><p><strong>浏览器缓存是 HTTP 缓存的一种具体实现</strong>（基于 HTTP 缓存机制实现），或者说，HTTP 缓存包含了浏览器缓存（私有缓存）和共享缓存（如代理服务器、CDN），两者通过 <code>Cache-Control</code> 的 <code>public/private</code> 及 <code>s-maxage</code> 等指令协同工作。因此，两者不是并列关系，而是<strong>包含关系</strong>。</p><h3 id="_2-6-localstorage、sessionstorage-和-cookie-的区别" tabindex="-1">2.6 localStorage、sessionStorage 和 cookie 的区别 <a class="header-anchor" href="#_2-6-localstorage、sessionstorage-和-cookie-的区别" aria-label="Permalink to &quot;2.6 localStorage、sessionStorage 和 cookie 的区别&quot;">​</a></h3><table><thead><tr><th style="text-align:left;">特性</th><th style="text-align:left;">localStorage</th><th style="text-align:left;">sessionStorage</th><th style="text-align:left;">cookie</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>存储容量</strong></td><td style="text-align:left;">约 5–10 MB（不同浏览器有差异）</td><td style="text-align:left;">约 5–10 MB</td><td style="text-align:left;">约 4 KB</td></tr><tr><td style="text-align:left;"><strong>生命周期</strong></td><td style="text-align:left;">永久存储，除非用户手动清除代码删除</td><td style="text-align:left;">当前会话（页面标签或浏览器关闭即清除）</td><td style="text-align:left;">可设置过期时间；未设置时，浏览器关闭即失效</td></tr><tr><td style="text-align:left;"><strong>作用域</strong></td><td style="text-align:left;">同源（协议 + 域名 + 端口）内所有标签页共享</td><td style="text-align:left;">同源且<strong>同一标签页</strong>（不同标签页不共享）</td><td style="text-align:left;">同源，并可设置 <code>path</code> 限制路径</td></tr><tr><td style="text-align:left;"><strong>与服务器的通信</strong></td><td style="text-align:left;">不会自动发送到服务器</td><td style="text-align:left;">不会自动发送到服务器</td><td style="text-align:left;">每次 HTTP 请求都会自动携带（通过 <code>Cookie</code> 请求头），会增加请求体积</td></tr><tr><td style="text-align:left;"><strong>操作 API</strong></td><td style="text-align:left;"><code>setItem/ getItem/ removeItem/ clear</code></td><td style="text-align:left;"><code>setItem/ getItem/ removeItem/ clear</code></td><td style="text-align:left;">需手动解析 <code>document.cookie</code> 字符串（无原生便捷方法）</td></tr><tr><td style="text-align:left;"><strong>安全性</strong></td><td style="text-align:left;">易受 XSS 攻击，但不会自动发送，可避免 CSRF</td><td style="text-align:left;">同左</td><td style="text-align:left;">可设置 <code>HttpOnly</code> 防止 XSS 读取，但存在 CSRF 风险；<code>Secure</code> 标志可限定 HTTPS 传输</td></tr></tbody></table><h2 id="_3-浏览器拓展" tabindex="-1">3. 浏览器拓展 <a class="header-anchor" href="#_3-浏览器拓展" aria-label="Permalink to &quot;3. 浏览器拓展&quot;">​</a></h2><h3 id="_3-1-javascript-的内存管理" tabindex="-1">3.1 JavaScript 的内存管理 <a class="header-anchor" href="#_3-1-javascript-的内存管理" aria-label="Permalink to &quot;3.1 JavaScript 的内存管理&quot;">​</a></h3><p>JavaScript 的内存管理是<strong>自动</strong>的，主要依赖<strong>垃圾回收器（Garbage Collector, GC）</strong> 来回收不再使用的内存。下面讲解其核心机制、常见问题及优化建议。</p><ol><li><p>内存生命周期</p><p>无论什么语言，内存生命周期都分为三步：</p><ol><li><strong>分配</strong>：声明变量、函数或创建对象时，JS 引擎自动分配内存。</li><li><strong>使用</strong>：读写变量、调用函数等操作。</li><li><strong>释放</strong>：当内存不再被需要时，垃圾回收器接管并释放它。</li></ol></li><li><p>垃圾回收（GC）主要算法</p><ol><li><strong>引用计数（早期、已被主流引擎抛弃）</strong><ul><li>原理：每个对象记录被引用的次数，次数为 0 时释放。</li><li>致命缺陷：<strong>循环引用</strong>（如两个对象互相引用）会导致计数永远不会归零，造成内存泄漏。</li><li>目前仅在老旧 IE（如 IE6-7）的某些 DOM 对象中存在此问题。</li></ul></li><li><strong>标记-清除（现代浏览器核心算法）</strong><ul><li>原理：从<strong>根</strong>（全局对象、当前执行栈的局部变量等）出发，递归标记所有能访问到的对象；未标记的即为不可达对象，直接清除。</li><li>优点：能正确处理循环引用（因为互相引用的对象若从根不可达，都会被标记为垃圾）。</li><li>缺点：内存碎片化、可能导致暂停（Stop-the-World），但现代 V8 通过<strong>增量标记</strong>、<strong>并发回收</strong>等优化了性能。</li></ul></li></ol></li><li><p>常见内存泄漏场景及避免方法</p><p>即使有 GC，如果代码中无意识地持续持有对象引用，仍会造成内存泄漏。</p><table><thead><tr><th style="text-align:left;">场景</th><th style="text-align:left;">示例</th><th style="text-align:left;">解决方案</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>意外全局变量</strong></td><td style="text-align:left;">未声明的变量 <code>function foo() { a = 10 }</code></td><td style="text-align:left;">使用 <code>&#39;use strict&#39;</code>；用完后 <code>delete</code> 或赋 <code>null</code></td></tr><tr><td style="text-align:left;"><strong>被遗忘的计时器 / 回调</strong></td><td style="text-align:left;"><code>setInterval</code> 中引用了大对象，但从未 <code>clearInterval</code></td><td style="text-align:left;">在组件销毁或不需要时及时清除</td></tr><tr><td style="text-align:left;"><strong>闭包</strong></td><td style="text-align:left;">函数内部引用外部大数组，且返回的函数长期持有该引用</td><td style="text-align:left;">审查闭包作用域，不再需要时解除引用（如将变量赋 <code>null</code>）</td></tr><tr><td style="text-align:left;"><strong>DOM 引用</strong></td><td style="text-align:left;">缓存了某个 DOM 节点，但该节点被移除后，变量仍引用它</td><td style="text-align:left;">使用弱引用（<code>WeakMap</code>/<code>WeakSet</code>），或手动赋 <code>null</code></td></tr><tr><td style="text-align:left;"><strong>脱离 DOM 树的节点</strong></td><td style="text-align:left;">一个 DOM 节点被移出文档，但 JS 中仍有变量引用它</td><td style="text-align:left;">同上，或直接删除引用</td></tr></tbody></table></li><li><p>辅助内存管理的工具与技巧</p><ul><li><strong><code>WeakMap</code> / <code>WeakSet</code></strong>：键名是弱引用，不影响垃圾回收。适用于数据缓存、DOM 关联数据。</li><li><strong>Chrome DevTools</strong>： <ul><li><strong>Performance</strong> 面板查看内存时间线；</li><li><strong>Memory</strong> 面板拍摄堆快照，比较对象引用与泄漏点。</li></ul></li></ul></li></ol><h3 id="_3-2-webkit-和-v8-的区别" tabindex="-1">3.2 WebKit 和 V8 的区别 <a class="header-anchor" href="#_3-2-webkit-和-v8-的区别" aria-label="Permalink to &quot;3.2 WebKit 和 V8 的区别&quot;">​</a></h3><p>WebKit 和 V8 是两个在浏览器领域至关重要但职责完全不同的项目。简单来说，WebKit 是一个浏览器的“总装车间”，<strong>负责处理页面的渲染和加载</strong>；而 V8 是其中的一个“核心零部件”，或者说一个高性能的“引擎”，专门<strong>负责执行 JavaScript 代码</strong>。</p><table><thead><tr><th style="text-align:left;">维度</th><th style="text-align:left;">🏢 WebKit</th><th style="text-align:left;">🚀 V8</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>项目性质</strong></td><td style="text-align:left;">一个<strong>浏览器引擎</strong>（或称渲染引擎），是个庞大的“操作系统”。</td><td style="text-align:left;">一个 <strong>JavaScript 执行引擎</strong>，是个专门的“虚拟机”。</td></tr><tr><td style="text-align:left;"><strong>核心职能</strong></td><td style="text-align:left;">将 HTML、CSS 转换为用户能看到的<strong>网页画面</strong>，并管理整个网页的生命周期。</td><td style="text-align:left;">读取、编译并执行网页中的 <strong>JavaScript 代码</strong>。</td></tr><tr><td style="text-align:left;"><strong>关键组件</strong></td><td style="text-align:left;">- <strong>WebCore</strong>：进行页面排版、计算布局的核心。<br>- <strong>JavaScriptCore</strong>：可选的 JS 引擎，能换成 V8 等。<br>- <strong>Ports</strong>：供不同平台集成的移植接口。</td><td style="text-align:left;">- <strong>Ignition</strong>：基础解释器，快速启动代码。<br>- <strong>TurboFan</strong>：优化编译器，提升代码性能。<br>- <strong>Orinoco</strong>：内存管理者，负责垃圾回收。</td></tr><tr><td style="text-align:left;"><strong>所属/用户</strong></td><td style="text-align:left;">苹果（Apple）主导并维护的开源项目。</td><td style="text-align:left;">Google 主导并维护的开源项目。</td></tr><tr><td style="text-align:left;"><strong>典型应用</strong></td><td style="text-align:left;">Safari浏览器、旧版Chrome浏览器（2013年前）。</td><td style="text-align:left;">Chrome浏览器、Microsoft Edge浏览器、Node.js 服务端环境。</td></tr><tr><td style="text-align:left;"><strong>语言侧重</strong></td><td style="text-align:left;">渲染、图形逻辑使用 C++ 实现。</td><td style="text-align:left;">编译器、运行时等核心部分使用 C++ 实现。</td></tr></tbody></table>`,51),s=[i];function n(a,d,g,c,f,p){return l(),e("div",null,s)}const x=t(r,[["render",n]]);export{y as __pageData,x as default};
